var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"강적이군. 이 몸이 한 번도 유효타를 먹이지 못하다니.","JPN":"強敵だな。オレ様が一発も攻撃を当てられないとは。","ENG":"A formidable foe. I haven't been able to get a hit in her once.","TWN":"好強，我完全打不到她。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안…… 나도 마찬가지야.","JPN":"ごめん……僕もだ。","ENG":"Sorry... Me too.","TWN":"抱歉……我也是。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"뭐해? 기세 좋게 등장 해놓고 벌써 지쳤어?","JPN":"何やってるの？　威勢よく登場しておいて、もうダウン？","ENG":"Hmm? Tired already? So you're all talk but no walk, eh?","TWN":"幹嘛？剛才出場時不是很有氣勢嗎？這麼快就累啦？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 아직 안 끝났다고.","JPN":"ちっ、まだこれからだぜ。","ENG":"Tch! It’s not over yet!","TWN":"嘖，才沒有！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"가지고 노는 건 그쯤해라, 레노어. 곧 손님이 올 테니.","JPN":"遊ぶのはその辺にしておけ、レノア。もうすぐ客人が来る。","ENG":"Lenore, stop wasting time. Our guests will arrive shortly.","TWN":"適可而止，蕾諾雅。客人就快到了。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네, 아버지.","JPN":"はい、お父様。","ENG":"Yes, father.","TWN":"是，父親。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……됐다. 이만 가자.","JPN":"……よし。もう行くぞ。","ENG":"...All right. Let's go.","TWN":"……算了，我們走吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 갑자기 어디로 간다는 말씀이십니까?","JPN":"え？　急にどちらに行かれるのですか？","ENG":"Huh? Where are we going?","TWN":"什麼？為什麼突然說要走？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주들이 패배한 뒤엔, 이곳 영지 또한 위험해진다.","JPN":"当主たちが負けたら、ここの領地も危険になる。","ENG":"Once the leaders of the families are defeated, the lands themselves will be in danger.","TWN":"堂主們失敗後，領地這裡也會變得很危險。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"여기서 다 죽을 수는 없는 노릇 아니냐?","JPN":"ここで皆殺しになるわけにはいかないじゃろう？","ENG":"We can't all die here, can we?","TWN":"總不能大家一起死在這裡吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"정 불안하다면 도망칠 것이 아니라 도우러 가야지요!","JPN":"不安なら逃げるのではなく、助けに行くべきでしょう！","ENG":"If you are that anxious, we should be there helping them! Not running away!","TWN":"如果您真的擔心，就應該去幫忙，而不是逃跑！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너, 나나하라 당주의 명령을 무시할 셈이냐?","JPN":"お主、七原当主の命令を無視するつもりか？","ENG":"Are you telling me that you're going to disobey Lady Nanahara's orders?","TWN":"你，打算無視七原堂主的命令嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"말했을 텐데?","JPN":"言ったはずじゃ。","ENG":"Have I not made it clear?","TWN":"我應該有說過吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신베기의 완성을 미루는 한이 있더라도, 나나하라 가문의 직계는 존속되어야 한다.","JPN":"大蛇薙剣の完成を後回しにしてでも、七原家の直系は残さなければならぬ。","ENG":"Even if we risk delaying the completion of Orochinagi, the Nanahara lineage must be preserved.","TWN":"就算可以暫緩完成瘟神斬的計畫，但前提是七原家族的直系必須活著。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 네놈도 이제 당주의 무사 노릇은 그만둬.","JPN":"お主ももう当主の護衛はやめることじゃ。","ENG":"So, whatever you're thinking of doing, don't.","TWN":"所以，你現在要卸下堂主的武士一職。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예정에 없던 아이가 태어나, 역신을 깨우리라……","JPN":"前例のない子どもが生まれ、疫病神の眠りを覚ますだろう……","ENG":"The unexpected child... shall awaken the Plague God.","TWN":"不在預期內出生的孩子，會喚醒瘟神……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"なに……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님께서도 분명 이 구절에 대해 알고 계시겠지요.","JPN":"ナオ様もきっとこの言葉をご存じでしょう。","ENG":"So you also know about this phrase.","TWN":"奈緒大人也應該知道這句話吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"초대 무녀의 예견? 그건 갑자기 왜……?","JPN":"初代巫女の予言？　いきなりなぜ……？","ENG":"The first priestess's prophecy? Why are you suddenly telling me that...?","TWN":"初代巫女的預言？你為何突然……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네 녀석……? 설마?","JPN":"お主……？　まさか？","ENG":"Wait... You don't mean...?!","TWN":"你這傢伙……？難道？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"본래 저는 살지 못할 운명이었으나, 어머니께서는 금기를 깨고 저를 태어나게 하셨습니다.","JPN":"本来私は死ぬ運命でしたが、母上は禁忌を破り私を生かしました。","ENG":"My fate was to die the day I was born. But Mother broke the rule and gave birth to me.","TWN":"我的命運本是該死的，是媽媽打破禁忌生下我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예견이 옳다면 저는 틀림없이 역신을 깨울 운명이지요.","JPN":"予言が正しければ私は必ず疫病神を目覚めさせるでしょう。","ENG":"If the prophecy is true, I am the one to awaken the Plague God.","TWN":"若預言是真的，那我的命運無疑就是要喚醒瘟疫。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그랬군. 그래서 나나하라 당주는 널 끌어들이지 않고 대신 움직이려 한 건가.","JPN":"そうか。だから七原当主はお主を引き込まずに代わりに動こうとしたのじゃな。","ENG":"I see. So that's why Lady Nanahara is trying so hard to pull you away from battle.","TWN":"原來如此，所以七原堂主才不想讓你牽扯進來，選擇替你行動嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저는 당주가 되어서도 안 되고, 사람들을 이끌 자격도 되지 않습니다.","JPN":"私は当主になってはならず、人を率いる資格もありません。","ENG":"I am not fit to be the head of the family, nor am I qualified enough to lead them.","TWN":"我不能成為堂主，也沒資格帶領別人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제 역할은 오로지…… 이 목숨을 바쳐 당주님을 지키는 것입니다.","JPN":"私の役割はただ……この命をかけて当主を守ることです。","ENG":"My sole purpose in life is... to protect Lady Nanahara with my life.","TWN":"我的職責就只是……獻出這條命保護堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"둘 중 하나가 살아남는다면, 그것은 제가 아니라 지금의 나나하라 당주님이어야 합니다.","JPN":"二人のうち一人が生き残らねばならないというなら、それは私ではなく今の七原当主でなければなりません。","ENG":"If only one is to survive, then it should be her and not me.","TWN":"若二人之中只能活下來一個，那必須是現在的七原堂主，而不是我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내 도움을 너무 기대하진 마라.","JPN":"わしにあまり期待するでないぞ。","ENG":"Don't expect me to help you out much.","TWN":"別想都靠我，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 못 쓰는 팔로 세울 수 있는 계획은 있는 거냐?","JPN":"腕が使えないのに策があるのか？","ENG":"But do you even have a plan in mind that will work with your one arm?","TWN":"憑你那條廢掉的手臂還想做什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"팔 하나로도 충분합니다.","JPN":"腕一本で十分です。","ENG":"One arm is more than enough.","TWN":"只有一隻手臂也沒問題。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"스승님을 도와, 검의 극의를 완성시켜 보일 테니까요.","JPN":"師匠を手伝い、剣の極意を完成して見せます。","ENG":"I will help my master, and reach the completion of my blade","TWN":"因為我會幫助師父完成劍的極致。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};